property.value:
# The java implementation to use. If JAVA_HOME is not found we expect java and jar to be in path
export JAVA_HOME={{java64_home}}

# Polaris JAAS configuration (used when Kerberos is enabled)
export POLARIS_JAAS_FILE={{polaris_jaas_conf}}

# Additional Java opts for Polaris, including Kerberos options when enabled.
# runtime/distribution/bin/{server,admin} consume POLARIS_JAVA_OPTS.
export POLARIS_OPTS="{{polaris_opts}} {{polaris_kerberos_opts}}"
export POLARIS_JAVA_OPTS="{{polaris_opts}} {{polaris_kerberos_opts}}"

# Polaris configuration directory
export POLARIS_CONF_DIR={{polaris_conf_dir}}
if [ -z "${QUARKUS_CONFIG_LOCATIONS:-}" ]; then
  export QUARKUS_CONFIG_LOCATIONS=${POLARIS_CONF_DIR}/application.properties,${POLARIS_CONF_DIR}/admin.properties
fi
if [ -z "${SMALLRYE_CONFIG_LOCATIONS:-}" ]; then
  export SMALLRYE_CONFIG_LOCATIONS=${QUARKUS_CONFIG_LOCATIONS}
fi

# Where log files are stored
export POLARIS_LOG_DIR={{polaris_log_dir}}
export QUARKUS_LOG_FILE_PATH={{polaris_log_dir}}/polaris.log

# PID dir
export POLARIS_PID_DIR={{polaris_pid_dir}}

# Data dir
export POLARIS_DATA_DIR={{polaris_data_dir}}

# Polaris home
export POLARIS_HOME={{polaris_home}}
export POLARIS_TOOLS_HOME={{polaris_tools_home}}

# Polaris TLS secret material
export POLARIS_SSL_ENABLED={{polaris_ssl_enabled}}
export POLARIS_SSL_AUTO_GENERATE={{polaris_ssl_auto_generate}}
export POLARIS_SSL_KEYSTORE_PASSWORD='{{polaris_ssl_keystore_password_escaped}}'
export POLARIS_SSL_TRUSTSTORE_PASSWORD='{{polaris_ssl_truststore_password_escaped}}'

# MCP server defaults
export POLARIS_BASE_URL={{polaris_mcp_base_url}}
export POLARIS_MCP_TRANSPORT={{polaris_mcp_transport}}
export POLARIS_MCP_HOST={{polaris_mcp_host}}
export POLARIS_MCP_PORT={{polaris_mcp_port}}
export POLARIS_MCP_TLS_ENABLED={{polaris_mcp_tls_enabled}}
export POLARIS_MCP_TLS_CERT_FILE={{polaris_mcp_tls_cert_file}}
export POLARIS_MCP_TLS_KEY_FILE={{polaris_mcp_tls_key_file}}
{% if polaris_mcp_tls_ca_file %}
export POLARIS_MCP_TLS_CA_FILE={{polaris_mcp_tls_ca_file}}
{% endif %}

# Console defaults
export POLARIS_CONSOLE_HOST={{polaris_console_host}}
export POLARIS_CONSOLE_PORT={{polaris_console_port}}
export POLARIS_CONSOLE_TLS_ENABLED={{polaris_console_tls_enabled}}
export POLARIS_CONSOLE_TLS_CERT_FILE={{polaris_console_tls_cert_file}}
export POLARIS_CONSOLE_TLS_KEY_FILE={{polaris_console_tls_key_file}}

# Default internal admin credentials (optional)
export POLARIS_ADMIN_USER={{polaris_admin_username}}
export POLARIS_ADMIN_PASSWORD='{{polaris_admin_password_escaped}}'
